SELECT card_type as cardType, COUNT(*) as transactionCount, SUM(actual_amount) as totalAmount, AVG(actual_amount) as avgAmount FROM fact_card_transactions WHERE 1=1
AND stat_year = #{year}
AND stat_month = #{month}
GROUP BY card_type ORDER BY transactionCount DESC

SELECT card_type as cardType,
       COUNT(*) as count,
       SUM(actual_amount) as totalAmount
FROM fact_card_transactions
WHERE stop_name = #{stopName}

    AND stat_year = #{year}


    AND stat_month = #{month}

GROUP BY card_type
ORDER BY count DESC

SELECT card_type as cardType,
       COUNT(*) as transactionCount,
       SUM(actual_amount) as totalRevenue
FROM fact_card_transactions
WHERE line_name = #{lineName}

    AND stat_year = #{year}


    AND stat_month = #{month}

GROUP BY card_type
ORDER BY transactionCount DESC
